export const GetEventsResponse = {
  toJsonObject(input: GetEventsResponse): any {
    return {
      nextLink: input.nextLink,
      value: input.value?.map((item) => Event.toJsonObject(item)),
    };
  },
  fromJsonObject(input: any): GetEventsResponse {
    return {
      nextLink: input.nextLink,
      value: input.value?.map((item: any) => Event.fromJsonObject(item)),
    };
  },
} as const;

export const PutEventRequest = {
  toJsonObject(input: PutEventRequest): any {
    return {
      timestamp: input.timestamp,
      attestation: SnpEvidence.toJsonObject(input.attestation),
      sign: input.sign,
      data: input.data,
    };
  },
  fromJsonObject(input: any): PutEventRequest {
    return {
      timestamp: input.timestamp,
      attestation: SnpEvidence.fromJsonObject(input.attestation),
      sign: input.sign as Sign,
      data: input.data,
    };
  },
} as const;

