export const Event = {
  toJsonObject(input: Event): any {
    return {
      timestamp: input.timestamp,
      timestamp_iso: input.timestampIso,
      scope: input.scope,
      id: input.id,
      seqno: input.seqno,
      data: input.data,
    };
  },
  fromJsonObject(input: any): Event {
    return {
      timestamp: input.timestamp,
      timestampIso: input.timestamp_iso,
      scope: input.scope,
      id: input.id,
      seqno: input.seqno,
      data: input.data,
    };
  },
} as const;

export const SnpEvidence = {
  toJsonObject(input: SnpEvidence): any {
    return {
      evidence: input.evidence,
      endorsements: input.endorsements,
      uvm_endorsements: input.uvmEndorsements,
      endorsed_tcb: input.endorsedTcb,
    };
  },
  fromJsonObject(input: any): SnpEvidence {
    return {
      evidence: input.evidence,
      endorsements: input.endorsements,
      uvmEndorsements: input.uvm_endorsements,
      endorsedTcb: input.endorsed_tcb,
    };
  },
} as const;
